// 读取文档内容用于语义检查
var doc = Application.ActiveDocument;
var content = '';
var paragraphs = doc.Paragraphs;
for (var i = 0; i < paragraphs.Count; i++) {
  var para = paragraphs.Item(i);
  content += para.Range.Text + '\n';
}
return { content: content.substring(0, 50000) }; // 限制长度避免超限

// 读取文档内容用于语义检查
var doc = Application.ActiveDocument;
if (!doc) return { error: '未找到活动文档' };
var content = '';
var paragraphs = doc.Paragraphs;
if (!paragraphs) return { error: '无法获取段落集合' };
for (var i = 1; i <= paragraphs.Count; i++) {
  var para = paragraphs.Item(i);
  if (para && para.Range) {
    content += para.Range.Text + '\n';
  }
}
return { content: content.substring(0, 50000) };
